// ─────────────────────────────────────────────────────────────────────────────
// Cover Letter Output Sanitizer
// Strips any AI reasoning / tool-call narration that appears before the date.
// Also detects the "asking for data" failure mode and returns a safe fallback.
// ─────────────────────────────────────────────────────────────────────────────

const raw = items[0].json.output
  || items[0].json.text
  || items[0].json.result
  || '';

// ── Detect failure mode: AI asked for more data instead of generating ──────
const askingForData = /please provide|i need the|to generate the cover letter|provide the json|can you share|provide.*fields|i'll need/i.test(raw);
if (askingForData) {
  return [{
    json: {
      success: false,
      generatedCoverLetter: raw,
      _note: 'AI requested additional data. Check n8n prompt rules.'
    }
  }];
}

// ── Strip preamble: find first line that starts with a date DD/MM/YYYY ──────
const lines = raw.split('\n');
let dateLineIndex = -1;
for (let i = 0; i < lines.length; i++) {
  // Allow optional whitespace before the date
  if (/^\s*\d{2}\/\d{2}\/\d{4}/.test(lines[i])) {
    dateLineIndex = i;
    break;
  }
}

let clean = raw.trim();
if (dateLineIndex > 0) {
  clean = lines.slice(dateLineIndex).join('\n').trim();
}

return [{
  json: {
    success: true,
    generatedCoverLetter: clean,
  }
}];
